const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

const INITIAL_ASSESSMENT_SURCHARGE = 0.10;
const PROCESSING_FEE = 5;

function ceilG(amount: number): number {
  return Math.ceil(amount - 1e-9);
}

export function processScenario(scenario: any): any {
  const results = scenario.steps.map((step: any) => {
    const basePremium = BASE_PREMIUMS[step.items[0].type];
    const premium = ceilG(basePremium * (1 + INITIAL_ASSESSMENT_SURCHARGE)) + PROCESSING_FEE;
    return { premium };
  });
  return { results };
}

