      } else {
        adjusted = basePremium * (1 - REPEAT_CONTRACT_DISCOUNT);
      }
      if (customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD) {
        adjusted *= (1 - LOYALTY_DISCOUNT);
