      policies[stepIndex] = {
        items: step.items,
        remainingCap: CAP_MULTIPLIER * computeInsuranceSum(step.items),
      };
      return { premium };
    }
    if (step.op === "claim") {
      return processClaim(step, policies[step.policy]);
